    p.add_argument("--flush-interval", type=float, default=float(os.environ.get("LOG_FLUSH_INTERVAL", str(DEFAULT_FLUSH_INTERVAL_SEC))))
    p.add_argument("--max-file-bytes", type=int, default=int(os.environ.get("LOG_MAX_FILE_BYTES", str(DEFAULT_MAX_FILE_BYTES))))
